import { convertNpzToObjTempFile, cleanupMeshTempFiles } from '../services/mesh_processor';
import { v4 as uuidv4 } from 'uuid';

/**
 * Quick test using the mesh_data from your Svix payload
 * Instructions for getting the full mesh data
 * TO RUN THIS TEST:
 * 1. Go to Svix URL: https://play.svix.com/view/e_8lU0bW67O3HS5ib8yGJoiBEx4p6
 * 2. Copy the FULL "mesh_data" value from the JSON payload
 * 3. Replace the SAMPLE_MESH_DATA constant above with the full Base64 string
 * 4. Run: npx ts-node src/tests/quick_npz_test.ts\n
 */
// Extracted mesh_data from Svix webhook 
const SAMPLE_MESH_DATA = ``; // This is truncated - you need the full Base64 string

async function quickTest() {
  console.log('Quick NPZ Conversion Test\n');
  
  const testJobId = uuidv4();
  const testUserId = "test_user_123";
  const testFilehash = "test_hash_abc";
  
  console.log(`Job ID: ${testJobId}`);
  console.log(`Expected filename: ${testUserId}_${testFilehash}_0.obj\n`);
  
  try {
    console.log('Starting conversion...');
    const startTime = Date.now();
    
    const result = await convertNpzToObjTempFile(
      SAMPLE_MESH_DATA,
      testJobId,
      testUserId,
      testFilehash,
      0
    );
    
    const endTime = Date.now();
    
    if (result.success) {
      console.log('SUCCESS!');
      console.log(`Processing time: ${endTime - startTime}ms`);
      console.log(`OBJ file created: ${result.objFilePath}`);
      console.log(`Content size: ${result.objContent?.length} characters`);
      
      if (result.objContent) {
        const lines = result.objContent.split('\n');
        const vertices = lines.filter(l => l.startsWith('v ')).length;
        const faces = lines.filter(l => l.startsWith('f ')).length;
        
        console.log(`🔺 Vertices: ${vertices}`);
        console.log(`🔸 Faces: ${faces}`);
        
        console.log('\nFirst few lines:');
        lines.slice(0, 8).forEach((line, i) => {
          console.log(`  ${i + 1}: ${line}`);
        });
      }
      
      // Cleanup disabled for inspection
      // await cleanupMeshTempFiles(testJobId);
      console.log('\nFiles preserved for inspection in temp_mesh/' + testJobId + '/');
      
    } else {
      console.log('FAILED!');
      console.log(`Error: ${result.error}`);
    }
    
  } catch (error) {
    console.log('Exception occurred:');
    console.error(error);
  }
}

if (require.main === module) {
  quickTest().catch(console.error);
}